#include<bits/stdc++.h>
using namespace std;
int a[200010],b[200010],d[200010];
int n,m;
vector<pair<int,int>> mp[200010];
vector<int> mp1[200010];
int in[200010],x[200010],y[200010];
stack<int> s;
bool instk[200010];
int dfn[200010],f[200010],low[200010],scccnt,scc[200010],siz[200010],val[200010],dfncnt;
vector<int> ans[200010];
void tarjan(int x,int fa)
{
    dfn[x]=low[x]=++dfncnt;
    instk[x]=true;
    s.push(x);
    for(auto i:mp[x])
    {
        int v=i.first,id=i.second;
        if(id==(fa^1))
        {
            continue;
        }
        if(!dfn[v])
        {
            tarjan(v,id);
            low[x]=min(low[x],low[v]);
        }
        else if(instk[v])
        {
            low[x]=min(low[x],dfn[v]);
        }
    }
    if(low[x]==dfn[x])
    {
        scccnt++;
        int top;
        do
        {
            top=s.top();
            s.pop();
            scc[top]=scccnt;
            siz[scccnt]++;
            instk[top]=false;
        }while(top!=x);
    }
}
void dfs(int x,int fa=0)
{
    d[x]=d[fa]+1;
    for(int i:mp1[x])
    {
        if(i!=fa)
        {
            dfs(i,x);
            a[x]+=a[i];
        }
    }
}
void dfs1(int x,int col)
{
    scc[x]=col;
    for(auto i:mp[x])
    {
        int v=i.first;
        if(!scc[v]&&b[i.second]==0)
        {
            dfs1(v,col);
        }
    }
}
int main()
{
    scanf("%d%d",&n,&m);
    for(int i=1;i<=m;i++)
    {
        int u,v;
        scanf("%d%d",&u,&v);
        x[i]=u;
        y[i]=v;
        mp[u].push_back(make_pair(v,i*2));
        mp[v].push_back(make_pair(u,i*2+1));
    }
    for(int i=1;i<=n;i++)
    {
        if(!dfn[i])
        {
            tarjan(i,-1);
        }
    }
    for(int i=1;i<=m;i++)
    {
        if(scc[x[i]]!=scc[y[i]])
        {
            mp1[scc[x[i]]].push_back(scc[y[i]]);
            mp1[scc[y[i]]].push_back(scc[x[i]]);
        }
    }
    int q;
    scanf("%d",&q);
    while(q--)
    {
        int u,v;
        scanf("%d%d",&u,&v);
        a[scc[u]]++;
        a[scc[v]]--;
    }
    for(int i=1;i<=scccnt;i++)
    {
        if(!d[i])
        {
            dfs(i);
        }
    }
    for(int i=1;i<=m;i++)
    {
        int u=x[i],v=y[i];
        if(scc[u]==scc[v])
        {
            printf("B");
            continue;
        }
        if(d[scc[u]]>d[scc[v]])
        {
            if(a[scc[u]]>0)
            {
                printf("R");
            }
            else if(a[scc[u]]==0)
            {
                printf("B");
            }
            else
            {
                printf("L");
            }
        }
        else
        {
            if(a[scc[v]]>0)
            {
                printf("L");
            }
            else if(a[scc[v]]==0)
            {
                printf("B");
            }
            else
            {
                printf("R");
            }
        }
    }
    return 0;
}
